import{_ as o,o as e,c as a,j as t,a as p,a1 as u}from"./chunks/framework.Bp7r_-XI.js";const c=JSON.parse('{"title":"高尤里","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/6.一次性血统/高尤里.md","filePath":"4.资源分区/1.血统与训练/6.一次性血统/高尤里.md"}'),n={name:"4.资源分区/1.血统与训练/6.一次性血统/高尤里.md"};function q(s,r,d,b,l,_){return e(),a("div",null,[...r[0]||(r[0]=[t("h1",{id:"高尤里",tabindex:"-1"},[p("高尤里 "),t("a",{class:"header-anchor",href:"#高尤里","aria-label":'Permalink to "高尤里"'},"​")],-1),t("table",{class:"bannerparthead"},[t("tbody",null,[t("tr",{id:"hdr"},[t("td",{class:"runninghead",nowrap:""},"TMD：新世短歌035")])])],-1),u('<h1 id="高尤里-1" tabindex="-1">高尤里 <a class="header-anchor" href="#高尤里-1" aria-label="Permalink to &quot;高尤里&quot;">​</a></h1><p>高尤里<br> 总描述：&quot;对了，千谣话。&quot;<br> &quot;嗯？怎么了前辈？&quot;<br> &quot;据我所知，高尤里会折射观测者渴望的形态。有人看见金发，有人看见黑发。你为何认定她是&#39;粉毛&#39;？&quot;</p><p>千谣话歪头：&quot;粉就是粉。什么意思？&quot;</p><p>这次轮到我困惑歪头。<br> 镜像般的动作让我们如同倒影。</p><p>&quot;你因发色称高尤里为&#39;粉毛&#39;对吧？&quot;<br> &quot;对啊&quot;<br> &quot;可你刚才说高尤里像宇宙本身。如此庞大的存在怎会有粉色头发？&quot;<br> 她眯起眼睛：&quot;所以我说是粉的啊&quot;</p><p>&quot;对，粉色&quot;<br> &quot;没错，粉色&quot;<br> &quot;？&quot;<br> &quot;？&quot;<br> 尴尬的沉默弥漫。</p><p>随后如闪电般，诡异的领悟击中我——不安的静电在脑海流窜。<br> 难道...<br> 不，太荒谬了。<br> 但若属实，就能解释为何我们始终鸡同鸭讲。<br> 我缓慢试探：&quot;高尤里...长着宇宙色的头发&quot;<br> 千谣话不假思索：&quot;对，粉头发&quot;</p><p>&quot;......&quot;</p><p>&quot;我一直这么说的啊前辈。它的头发是粉色。那是无法描述的颜色，所以我称之为粉。不代表真实存在粉色。你平时很懂比喻的，怎么不明白？&quot;</p><p>价格：A+8000<br> 描述：高尤里是被形容为“宇宙所有生物信息素的统合”的生命体，客观存在，只要被观测就能构筑出观测者眼中“最完美的人的形象”，展现出的能力包括被动催眠，主动控制，模因污染，生物同化，改变感知，灵魂寄生。所幸，这一版本并不具有原本毁灭世界的同化性与功能。<br> 特性：【认知生命体】【最完美的“人”】</p><p>【认知生命体】：“如果你观测到高尤里是白头发，而另一个人还没观测到高尤里，但他心中最完美的形象是黑发，你对他介绍高尤里，说它是个白头发的人，而那个人只会听到你说高尤里是个黑头发的人。”</p><p>“哪怕你根本没有在描述跟高尤里有关的客观现实，比如说它是个有蓝色头发的人，他还是只会听到“高尤里是个有黑头发的人”。只要你在形容高尤里，无论正确与否，对方认知到的就只会是“最完美的人的形象”。”</p><p>任何与你进行过接触的单位，皆需要使用意志豁免对抗你的【风度+技能：社交+专业：交际】，若失败则其视为被【模因】效果所影响；在被影响的单位眼中，你会越来越接近于其心目中的【最完美的人】，不仅是外观、包括性格表现在内，对方完全不会意识到你的变化有什么问题，这一变化周期通常需要十五分钟的相处，且你只会在被模因效果所影响的人眼中视为【最完美的人】。</p><p>注意，这并不影响你在进行行动和交涉时会对其态度产生的影响，只代表对方会觉得你的样貌与表现很符合自己心目中喜好的类型，并不觉得有什么异常之处。但也因为不觉得有什么异常之处，会导致其下意识的忽略你在不合时宜与在不该出现的地方所出现的问题，除非这涉及到了其生命危险、或者违背了对方最基础的观念（例如一个杀人无算的颠子虽然看你顺眼但不妨碍你出现在他面前时，他只会恭敬的杀了你；一个对主君忠心到深入骨髓的死士，也会在你出现在危害到他主君的地方时直接攻击你；在一个不允许进入的军事重地中，尽职尽责的守卫依旧会对你鸣枪示警并且进行抓捕等等），并且显然的，这一能力不算做反侦测效果，你并不能因此满足反侦测的条件或者借此获得一些在规则上只有反侦测才能带来的好处，除非ST认为你可以完成（例如在处理满足突袭轮条件的部分上）。</p><p>若被影响的人试图向其他人描述你的时候（无论是语言，还是文字，包括照片等内容，这一效果传播的途径是信息），听到描述的人同样需要进行一次意志豁免对抗上述提及你进行的检定，失败则其同样视为感染了这一模因影响，会在周期内逐级对你的认知有所改变，即认为你的相貌接近于认知中【最完美的人】。</p><p>上述效果皆视为一个A级信息来源的【模因】效果；由于原典表现，这一【模因】效果的影响范围无法跨越国家，因此只会在你所位于的国家地区内产生影响。</p><p>【最完美的“人”】：购买这一血统后，你的的真名不可避免的变更为【高尤里】，因为你已经成为了高尤里在此处的所被观测的“化身”，你依旧保留了自己的意识。</p><p>你在外貌上获得等同自身【风度属性】的提升，同时可以使用当前风度值重新决定一次基础外貌值；任何与你第一次见面的单位，若其对你的初始好感度不为极端等级（即敌视，仇视），则会向上调整等同你的【传奇风度】+1级，最高不会提升至极端态度（即最高不会高于友善）。</p><p>在进入战斗后，每轮结束时你的外貌都会提升5点，至多提升你的风度属性*5点外貌，直到战斗结束后因此提升的外貌清空；在战斗中，每当你的攻击命中后，都可以使用【风度+技能：社交+专业：交际】与目标的意志豁免对抗，若目标对抗失败，将会主动攻击自己的队友，直到场上仅剩下目标单位而无其他队友之前，目标无法正确的将你当做敌人看待，这是一个A级信息来源的【支配】效果。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',21)])])}const h=o(n,[["render",q]]);export{c as __pageData,h as default};
